const body = $input.first().json.body || $input.first().json;
const strategy = body.strategy;
const pair = body.pair || 'BTC/USDT';
const startDate = body.startDate || new Date(Date.now() - 90 * 24 * 60 * 60 * 1000).toISOString().split('T')[0];
const endDate = body.endDate || new Date().toISOString().split('T')[0];
const initialCapital = body.initialCapital || 10000;

if (!strategy) throw new Error('Missing strategy in request body');

return [{ json: { strategy, pair, startDate, endDate, initialCapital } }];

const result = $input.first().json;
const params = $('Parse Request').first().json;

const sharpe = result.sharpeRatio || result.sharpe_ratio || 0;
const totalReturn = result.totalReturn || result.total_return || 0;
const maxDrawdown = result.maxDrawdown || result.max_drawdown || 0;
const totalTrades = result.totalTrades || result.total_trades || 0;
const winRate = result.winRate || result.win_rate || 0;
const profitFactor = result.profitFactor || result.profit_factor || 0;

const passed = sharpe >= 0.5;

let report = `BACKTEST RESULTS\n`;
report += `${'='.repeat(35)}\n\n`;
report += `Strategy: ${params.strategy}\n`;
report += `Pair: ${params.pair}\n`;
report += `Period: ${params.startDate} to ${params.endDate}\n`;
report += `Initial Capital: $${params.initialCapital.toLocaleString()}\n\n`;

report += `PERFORMANCE\n`;
report += `  Total Return: ${(totalReturn * 100).toFixed(2)}%\n`;
report += `  Sharpe Ratio: ${sharpe.toFixed(3)} ${passed ? 'PASS' : 'FAIL (< 0.5)'}\n`;
report += `  Max Drawdown: ${(maxDrawdown * 100).toFixed(2)}%\n`;
report += `  Profit Factor: ${profitFactor.toFixed(2)}\n\n`;

report += `TRADES\n`;
report += `  Total: ${totalTrades}\n`;
report += `  Win Rate: ${(winRate * 100).toFixed(1)}%\n`;

if (result.equityCurve) {
  const finalEquity = result.equityCurve[result.equityCurve.length - 1]?.value || 0;
  report += `  Final Equity: $${Number(finalEquity).toLocaleString()}\n`;
}

return [{
  json: {
    report,
    passed,
    sharpe,
    strategy: params.strategy,
    chatId: process.env.TELEGRAM_ALERT_CHAT_ID || ''
  }
}];
